import{_ as t,c as n,o as s,aj as l}from"./chunks/framework.CynFBi0q.js";const c=JSON.parse('{"title":"第12章 AI 产品经理求职指南","description":"","frontmatter":{},"headers":[],"relativePath":"handbook/ai-agent-product/chapter_12.md","filePath":"handbook/ai-agent-product/chapter_12.md","lastUpdated":1781970092000}'),i={name:"handbook/ai-agent-product/chapter_12.md"};function p(e,a,r,d,o,h){return s(),n("div",null,[...a[0]||(a[0]=[l(`<h1 id="第12章-ai-产品经理求职指南" tabindex="-1">第12章 AI 产品经理求职指南 <a class="header-anchor" href="#第12章-ai-产品经理求职指南" aria-label="Permalink to “第12章 AI 产品经理求职指南”">​</a></h1><p>想做AI产品经理的人很多，但岗位并没有想象中多。这不是因为行业不需要人，而是行业需要真正懂AI、能落地的产品经理，而不是只会写PRD的传统PM。</p><p>我是怕浪猫，这章不讲虚的，只讲求职AI产品经理的实战路径。</p><h2 id="_12-1-职业定位" tabindex="-1">12.1 职业定位 <a class="header-anchor" href="#_12-1-职业定位" aria-label="Permalink to “12.1 职业定位”">​</a></h2><h3 id="ai-赛道个人定位选择" tabindex="-1">AI 赛道个人定位选择 <a class="header-anchor" href="#ai-赛道个人定位选择" aria-label="Permalink to “AI 赛道个人定位选择”">​</a></h3><p>AI产品经理不是单一岗位，而是包含多种方向的职位集合。你需要先知道自己适合哪个方向。</p><p>AI产品经理的主要方向：</p><table tabindex="0"><thead><tr><th>方向</th><th>核心工作</th><th>技术要求</th><th>适合人群</th></tr></thead><tbody><tr><td>AI平台PM</td><td>大模型平台、API平台、模型服务</td><td>较高</td><td>有技术背景</td></tr><tr><td>AI应用PM</td><td>面向用户的AI产品（对话、办公、创作）</td><td>中等</td><td>有C端产品经验</td></tr><tr><td>AI行业PM</td><td>垂直行业AI（医疗、金融、教育）</td><td>中等</td><td>有行业经验</td></tr><tr><td>AI数据PM</td><td>数据构建、数据标注、评测体系</td><td>中高</td><td>有数据背景</td></tr><tr><td>AI增长PM</td><td>用户增长、商业化、运营工具</td><td>中低</td><td>有增长/运营经验</td></tr><tr><td>AI基础设施PM</td><td>算力平台、MLOps、工具链</td><td>高</td><td>工程/运维背景</td></tr></tbody></table><p>选择方向的原则：</p><ol><li>技术背景强 → 平台/基础设施方向</li><li>行业经验深 → 行业AI方向</li><li>用户感觉好 → 应用/增长方向</li><li>数据能力强 → 数据/评测方向</li></ol><h3 id="ai-非技术赛道招聘需求详解" tabindex="-1">AI 非技术赛道招聘需求详解 <a class="header-anchor" href="#ai-非技术赛道招聘需求详解" aria-label="Permalink to “AI 非技术赛道招聘需求详解”">​</a></h3><p>很多人对AI产品经理有误解，觉得必须会写代码。实际上，非技术背景的AI产品经理需求量很大，但需要的能力不同。</p><p>非技术赛道更看重：</p><ul><li>对AI能力的理解：知道什么能做，什么不能做</li><li>对场景的敏感度：能找到AI能创造价值的场景</li><li>用户沟通能力：能把AI技术翻译成用户价值</li><li>数据驱动意识：能用数据证明AI的价值</li><li>伦理和安全意识：理解AI的边界和风险</li></ul><p>招聘JD中的高频要求：</p><table tabindex="0"><thead><tr><th>能力</th><th>出现频率</th><th>说明</th></tr></thead><tbody><tr><td>产品规划</td><td>90%</td><td>制定产品路线、功能优先级</td></tr><tr><td>需求分析</td><td>85%</td><td>用户调研、竞品分析、需求拆解</td></tr><tr><td>AI技术理解</td><td>80%</td><td>理解大模型、RAG、Agent</td></tr><tr><td>数据分析</td><td>70%</td><td>埋点、AB测试、指标体系</td></tr><tr><td>项目管理</td><td>70%</td><td>跨团队协作、推动项目落地</td></tr><tr><td>提示词工程</td><td>50%</td><td>能写高质量提示词</td></tr><tr><td>商业化思维</td><td>40%</td><td>成本意识、定价策略</td></tr></tbody></table><p>注意：不同方向的JD差异很大。平台PM的JD会强调API设计和开发者生态，应用PM的JD会强调用户体验和增长，行业PM的JD会强调行业know-how。</p><h3 id="产品职业生涯常见困惑解答" tabindex="-1">产品职业生涯常见困惑解答 <a class="header-anchor" href="#产品职业生涯常见困惑解答" aria-label="Permalink to “产品职业生涯常见困惑解答”">​</a></h3><p><strong>困惑1：不会写代码能不能做AI产品经理？</strong> 可以。但你需要理解代码的基本逻辑、能读懂API文档、能和技术团队用技术语言沟通。不要求你写生产代码，但要求你能理解技术边界。</p><p><strong>困惑2：传统产品经理怎么转型AI产品经理？</strong> 最短路径是：</p><ol><li>学习AI基础知识（大模型、RAG、Agent）</li><li>用AI工具做个人项目（哪怕只是用Dify搭一个简单应用）</li><li>在原工作中寻找AI落地场景，主导一个小项目</li><li>把项目经验写入简历和面试案例</li></ol><p><strong>困惑3：AI产品经理和算法产品经理的区别？</strong> AI产品经理更偏向应用层，关注用户需求、产品体验、商业化。算法产品经理更偏向技术层，关注模型选型、效果优化、算法流程。两者有重叠，但侧重点不同。</p><p><strong>困惑4：大厂还是小厂？</strong></p><ul><li>大厂：规范、资源多、能接触大项目，但可能做螺丝钉</li><li>小厂：机会多、成长快、能端到端负责，但资源有限、风险高</li><li>建议：应届生/转型期优先大厂学习；有经验后小厂更适合发挥</li></ul><h2 id="_12-2-求职实战" tabindex="-1">12.2 求职实战 <a class="header-anchor" href="#_12-2-求职实战" aria-label="Permalink to “12.2 求职实战”">​</a></h2><h3 id="ai-产品经理简历准备技巧" tabindex="-1">AI 产品经理简历准备技巧 <a class="header-anchor" href="#ai-产品经理简历准备技巧" aria-label="Permalink to “AI 产品经理简历准备技巧”">​</a></h3><p>简历是敲门砖。AI产品经理的简历需要突出&quot;AI相关能力&quot;。</p><p>简历结构：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>1. 个人信息（姓名、联系方式、作品集链接）</span></span>
<span class="line"><span>2. 求职意向（AI产品经理 + 细分方向）</span></span>
<span class="line"><span>3. 个人简介（3-5行，突出AI产品经验和核心优势）</span></span>
<span class="line"><span>4. 工作经历（倒序，STAR法则，量化成果）</span></span>
<span class="line"><span>5. AI项目经验（单独列出，详细描述）</span></span>
<span class="line"><span>6. 教育背景</span></span>
<span class="line"><span>7. 技能清单（AI相关技能优先）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>简历写作的3个原则：</p><p><strong>原则1：量化成果</strong> 不要写&quot;负责AI客服产品&quot;，要写&quot;主导AI客服产品，独立解决率从40%提升到65%，转人工率下降30%&quot;</p><p><strong>原则2：突出AI相关能力</strong> 在简历中明确提到：大模型、RAG、Agent、提示词工程、数据标注、AI评测、AB测试等关键词。</p><p><strong>原则3：项目要有完整闭环</strong> 不要只写&quot;做过AI产品&quot;，要写出：需求分析→方案设计→技术选型→效果验证→迭代优化，证明你做过端到端的项目。</p><p>AI项目经验描述模板：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>项目名称：AI客服助手</span></span>
<span class="line"><span>项目背景：客服团队每天处理1000+咨询，人工成本高，响应慢</span></span>
<span class="line"><span>我的角色：产品负责人</span></span>
<span class="line"><span></span></span>
<span class="line"><span>工作内容：</span></span>
<span class="line"><span>1. 需求分析：通过用户访谈和数据分析，识别Top 10高频问题场景</span></span>
<span class="line"><span>2. 方案设计：设计RAG+Agent客服架构，覆盖FAQ、订单查询、退货处理</span></span>
<span class="line"><span>3. 技术协作：与技术团队确定模型选型（Embedding + Rerank + LLM）和工具调用方案</span></span>
<span class="line"><span>4. 数据准备：构建知识库，标注500条测试数据，设计评测指标体系</span></span>
<span class="line"><span>5. 效果验证：独立解决率65%，转人工率下降30%，用户满意度4.2/5</span></span>
<span class="line"><span>6. 迭代优化：根据Badcase分析优化提示词和检索策略，持续迭代</span></span>
<span class="line"><span></span></span>
<span class="line"><span>项目成果：</span></span>
<span class="line"><span>- 客服成本下降25%</span></span>
<span class="line"><span>- 平均响应时间从5分钟降到30秒</span></span>
<span class="line"><span>- 获得团队年度优秀项目</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br></div></div><h3 id="ai-产品经理项目与面试准备技巧" tabindex="-1">AI 产品经理项目与面试准备技巧 <a class="header-anchor" href="#ai-产品经理项目与面试准备技巧" aria-label="Permalink to “AI 产品经理项目与面试准备技巧”">​</a></h3><p>没有项目经验？自己造一个。</p><p>推荐个人项目：</p><ol><li>用Dify搭建一个垂直知识库问答系统（比如健身、法律、育儿）</li><li>用Coze做一个生活助手Agent（比如旅行规划、菜谱推荐）</li><li>做一个AI评测项目（对比不同模型在特定任务上的表现）</li><li>复刻一个热门AI产品的核心流程（比如AI会议纪要、AI客服）并写分析文章</li></ol><p>这些项目不需要写代码，但能证明你理解AI产品从0到1的过程。</p><p>面试准备框架：</p><p><strong>1. 项目深挖</strong> 面试官会针对你的项目问细节：</p><ul><li>为什么选这个模型？</li><li>知识库是怎么构建的？</li><li>怎么评测效果的？</li><li>遇到过什么失败？怎么解决的？</li><li>如果重来一次，你会怎么做？</li></ul><p>准备这些问题时，要有具体数据支撑。比如&quot;Embedding用的是bge-large-zh，Rerank用的是bge-reranker-large，Top-K取5，评测集有300条真实用户问题，准确率从0.72提升到0.85&quot;。</p><p><strong>2. 产品思维题</strong></p><ul><li>&quot;如果让你做AI导游，你会怎么设计？&quot;</li><li>&quot;AI客服怎么做才能真正减少人工？&quot;</li><li>&quot;怎么评估一个AI功能是否值得上线？&quot;</li></ul><p>回答思路：用户需求 → 场景 → 方案 → 指标 → 风险。</p><p><strong>3. 技术理解题</strong></p><ul><li>&quot;RAG和微调的区别是什么？&quot;</li><li>&quot;怎么解决AI幻觉？&quot;</li><li>&quot;Agent和Workflow的区别？&quot;</li><li>&quot;怎么设计提示词让模型输出更稳定？&quot;</li></ul><p>回答思路：不要讲太深奥的技术细节，重点讲产品层面的理解和权衡。</p><p><strong>4. 案例讨论题</strong></p><ul><li>&quot;分析一下ChatGPT的某个功能设计&quot;</li><li>&quot;评价一个你做过的竞品&quot;</li><li>&quot;如果AI回答错了，产品层面怎么处理？&quot;</li></ul><p>回答思路：结构化分析，给出明确观点，而不是面面俱到。</p><h3 id="面试中的加分项和减分项" tabindex="-1">面试中的加分项和减分项 <a class="header-anchor" href="#面试中的加分项和减分项" aria-label="Permalink to “面试中的加分项和减分项”">​</a></h3><p>加分项：</p><ul><li>能清晰区分&quot;用户想要的&quot;和&quot;AI能做的&quot;</li><li>能说出具体的AI评测指标和优化经历</li><li>有安全意识（隐私、数据、伦理）</li><li>能讲清楚项目的商业价值和成本</li><li>能承认自己不懂的地方，不强行装逼</li></ul><p>减分项：</p><ul><li>对大模型能力边界认知不清（&quot;AI什么都能做&quot;）</li><li>只关注功能，不关注数据和效果</li><li>忽视AI的安全和伦理问题</li><li>简历项目一看就是抄的，没有自己的思考</li><li>无法解释技术方案的选择原因</li></ul><p><strong>本章小结</strong></p><table tabindex="0"><thead><tr><th>主题</th><th>核心要点</th></tr></thead><tbody><tr><td>职业方向</td><td>平台/应用/行业/数据/增长/基础设施，6大方向</td></tr><tr><td>非技术赛道</td><td>更看重场景理解、用户沟通、数据驱动</td></tr><tr><td>简历原则</td><td>量化成果、突出AI、完整闭环</td></tr><tr><td>项目经验</td><td>没项目就自己做Dify/Coze项目</td></tr><tr><td>面试准备</td><td>项目深挖、产品思维、技术理解、案例讨论</td></tr><tr><td>加分项</td><td>懂AI边界、有评测经验、有安全意识</td></tr><tr><td>减分项</td><td>盲目崇拜AI、忽视数据、项目抄袭</td></tr></tbody></table><p>觉得有用？收藏起来，下次直接照抄。</p><p>你正在准备AI产品经理求职吗？评论区聊聊你的困惑。</p><p>关注怕浪猫，下期我们讲AI前沿动态与行业洞察。</p><p>系列进度 12/13</p><p><strong>下章预告：</strong> 第13章AI前沿动态与行业洞察，包括OS Agent、Vibe Coding、Claude Skills、本地AI等最新趋势。</p>`,65)])])}const u=t(i,[["render",p]]);export{c as __pageData,u as default};
